#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int countSubsequences(int* A, int N, int* B, int M) {
    int count = 0;
    for (int mask = 0; mask < (1 << N); mask++) {
        int subsequence[M];
        int size = 0;
        for (int i = 0; i < N; i++) {
            if ((mask & (1 << i)) != 0) {
                subsequence[size++] = A[i];
            }
        }
        if (size != M) continue;
        int valid = 1;
        for (int i = 0; i < M; i++) {
            if (i > 0 && subsequence[i] + B[i] < subsequence[i-1] + B[i-1]) {
                valid = 0;
                break;
            }
        }
        if (valid) count = (count + 1) % MOD;
    }
    return count;
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int* A = (int*)malloc(N * sizeof(int));
    int* B = (int*)malloc(M * sizeof(int));
    for (int i = 0; i < N; i++) scanf("%d", &A[i]);
    for (int i = 0; i < M; i++) scanf("%d", &B[i]);
    qsort(A, N, sizeof(int), compare);
    printf("%d\n", countSubsequences(A, N, B, M));
    free(A);
    free(B);
    return 0;
}

