public class Main {
    static final int MOD = 1000000007;
    public static int countSubsequences(int[] A, int N, int[] B, int M) {
        int count = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int[] subsequence = new int[M];
            int size = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    subsequence[size++] = A[i];
                }
            }
            if (size != M) continue;
            int valid = 1;
            for (int i = 0; i < M; i++) {
                if (i > 0 && subsequence[i] + B[i] < subsequence[i-1] + B[i-1]) {
                    valid = 0;
                    break;
                }
            }
            if (valid) count = (count + 1) % MOD;
        }
        return count;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        int[] A = new int[N];
        int[] B = new int[M];
        for (int i = 0; i < N; i++) A[i] = scanner.nextInt();
        for (int i = 0; i < M; i++) B[i] = scanner.nextInt();
        Arrays.sort(A);
        System.out.println(countSubsequences(A, N, B, M));
    }
